// Recebe itens, classifica e devolve um array de itens
return items.map(item => {
  const bin = item.binary || {};
  const firstKey = Object.keys(bin)[0];
  const b = firstKey ? bin[firstKey] : {};
  const mt = (b.mimeType || '').toLowerCase();
  const main = mt.split('/')[0];

  let mediaType;

  if (['image', 'video', 'audio'].includes(main)) {
    mediaType = main;
  } else {
    const subtype = (mt.split('/')[1] || '');
    const docApps = [
      'pdf','msword','rtf','json','xml','csv',
      'vnd.openxmlformats-officedocument.wordprocessingml.document',
      'vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      'vnd.openxmlformats-officedocument.presentationml.presentation',
      'vnd.ms-excel','vnd.ms-powerpoint','zip','x-7z-compressed',
      'x-rar-compressed','x-tar'
    ];

    if (main === 'text') mediaType = 'document';
    else if (main === 'application' && docApps.some(s => subtype.includes(s))) mediaType = 'document';
    else {
      // Fallback por extensão
      const name = decodeURIComponent(b.fileName || item.json?.fileName || '');
      const ext = (name.split('.').pop() || '').toLowerCase();

      if (['jpg','jpeg','png','gif','webp','bmp','tiff','svg','heic','heif','avif'].includes(ext)) mediaType = 'image';
      else if (['mp4','mov','m4v','mkv','avi','webm','flv','wmv'].includes(ext)) mediaType = 'video';
      else if (['mp3','wav','m4a','aac','ogg','oga','flac','amr','opus','wma'].includes(ext)) mediaType = 'audio';
      else mediaType = 'document';
    }
  }

  // Anexa a classificação no JSON do item
  item.json = { ...(item.json || {}), mediaType };
  return item;
});

