// JSON que será personalizado
const origem = $input.first().json;

// Config de personalização
const cfg = $('PERSONALIZAR SAAS').first().json.body || {};

// Lista de substituições
const replaces = [];

// Escapa regex
function escapeRegExp(str) {
  return String(str).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Campos fixos
const camposFixos = [
  ['corAtual', 'corNova'],
  ['rgbAtual', 'rgbNovo'],
  ['nomeAtual', 'nomeNova'],
  ['logoAtual', 'logoNova'],
  ['faviconeAtual', 'faviconeNova'],
  ['telefoneSuporteAtual', 'telefoneSuporteNova'],
];

// Adiciona substituições dos campos fixos
for (const [atualKey, novaKey] of camposFixos) {
  const atual = cfg[atualKey];
  const nova = cfg[novaKey];

  if (atual != null && nova != null && String(atual) !== '') {
    replaces.push({
      buscar: String(atual),
      trocar: String(nova),
      caseInsensitive: atualKey === 'corAtual', // só cor hex fica case-insensitive
    });

    // Se a cor vier sem #, adiciona também versão com #
    if (atualKey === 'corAtual') {
      const atualStr = String(atual);
      const novaStr = String(nova);

      if (!atualStr.startsWith('#')) {
        replaces.push({
          buscar: `#${atualStr}`,
          trocar: `#${novaStr}`,
          caseInsensitive: true,
        });
      }
    }
  }
}

// Adiciona substituições dinâmicas dos vídeos
if (Array.isArray(cfg.videos)) {
  for (const video of cfg.videos) {
    if (
      video &&
      video.urlAtual != null &&
      video.urlNova != null &&
      String(video.urlAtual) !== ''
    ) {
      replaces.push({
        buscar: String(video.urlAtual),
        trocar: String(video.urlNova),
        caseInsensitive: false,
      });
    }
  }
}

// Remove duplicados
const seen = new Set();
const replacesUnicos = replaces.filter((item) => {
  const key = `${item.buscar}|||${item.trocar}|||${item.caseInsensitive}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Ordena do maior para o menor para evitar conflito parcial
replacesUnicos.sort((a, b) => b.buscar.length - a.buscar.length);

// Aplica replace em string
function applyReplacements(text, rules) {
  let out = text;

  for (const rule of rules) {
    if (rule.caseInsensitive) {
      out = out.replace(
        new RegExp(escapeRegExp(rule.buscar), 'gi'),
        rule.trocar
      );
    } else {
      out = out.replaceAll(rule.buscar, rule.trocar);
    }
  }

  return out;
}

// Replace recursivo em todo o JSON
function deepReplace(value, rules) {
  if (typeof value === 'string') {
    return applyReplacements(value, rules);
  }

  if (Array.isArray(value)) {
    return value.map(item => deepReplace(item, rules));
  }

  if (value && typeof value === 'object') {
    const obj = {};
    for (const [k, v] of Object.entries(value)) {
      obj[k] = deepReplace(v, rules);
    }
    return obj;
  }

  return value;
}

const resultado = deepReplace(origem, replacesUnicos);

return [
  {
    json: resultado
  }
];

